```javascript
// Function to show chat history
function showChatHistory(history) {
  const chatHistory = document.getElementById('chat-history');
  chatHistory.innerHTML = '';

  history.forEach((msg, index) => {
    const div = document.createElement('div');
    div.textContent = msg;
    chatHistory.appendChild(div);
  });
}

// Function to send message
function sendMessage() {
  const userMessage = document.getElementById('user-message').value;
  const chatHistory = document.getElementById('chat-history');
  chatHistory.innerHTML += `<div>You: ${userMessage}</div>`;

  // Simulate AI response
  const botMessage = "Hello there! How can I assist you today?";
  chatHistory.innerHTML += `<div>Bot: ${botMessage}</div>`;

  // Show chat history in modal
  const chatModal = document.getElementById('chat-modal');
  chatModal.style.display = "block";

  // Add previous messages to chat history
  showChatHistory([userMessage, botMessage]);

  // Clear input field after sending message
  document.getElementById('user-message').value = '';

  // Optional: Scroll to the bottom of chat history
  chatHistory.scrollTop = chatHistory.scrollHeight;
}

// Close chat history modal
function closeChatModal() {
  const chatModal = document.getElementById('chat-modal');
  chatModal.style.display = "none";
}
```

